        return NextResponse.json({ subscription: sub, payments, role: session.role ?? null });
    } catch {
        return NextResponse.json({ subscription: null, payments: [], role: null });
    }
}

// 구독 해지
export async function DELETE() {
    const session = await getServerSession();
    if (!session?.dbId) return NextResponse.json({ error: "로그인이 필요합니다." }, { status: 401 });

    try {
        const existing = await prisma.subscription.findUnique({ where: { userId: session.dbId } });
        if (!existing || existing.status !== "ACTIVE") {
            return NextResponse.json({ error: "구독 중이 아닙니다." }, { status: 400 });
        }

        // 구독 취소
        await prisma.subscription.update({
            where: { userId: session.dbId },
            data: { status: "CANCELLED", cancelledAt: new Date() },
        });

        // 프로필 사진 초기화 (role 기반)
        const resetAvatarUrl = session.role === "CREATOR" ? "/creator.png" : null;
        await prisma.$executeRaw`
            UPDATE "User" SET "avatarUrl" = ${resetAvatarUrl}, "updatedAt" = NOW()
            WHERE id = ${session.dbId}
        `;

        return NextResponse.json({ ok: true });
    } catch (e) {
        console.error(e);
        return NextResponse.json({ error: "해지 처리 중 오류가 발생했습니다." }, { status: 500 });
    }
}

import { NextRequest, NextResponse } from "next/server";
import { getServerSession } from "@/lib/session";
import { prisma } from "@/lib/prisma";
import { createHmac } from "crypto";
import { SESSION_COOKIE_NAME, SESSION_MAX_AGE_SECONDS } from "@/lib/constants";

const MAX_SIZE_BYTES = 2 * 1024 * 1024; // 2MB

function signSession(payload: Record<string, unknown>, secret: string) {
    const json = JSON.stringify(payload);
    const signature = createHmac("sha256", secret).update(json).digest("base64url");
    return `${Buffer.from(json).toString("base64url")}.${signature}`;
}

// 프로필 이미지 업로드 (Base64 dataURL)
export async function PATCH(req: NextRequest) {
    const session = await getServerSession();
    if (!session?.dbId) {
        return NextResponse.json({ error: "로그인이 필요합니다." }, { status: 401 });
    }

    // PRO 구독자 또는 ADMIN만 프로필 사진 변경 가능
    const { avatarUrl } = body;

    // null이면 삭제 (카카오 이미지로 복귀)
    if (avatarUrl !== null && avatarUrl !== undefined) {
        // dataURL 형식 검사
        if (!avatarUrl.startsWith("data:image/")) {
            return NextResponse.json({ error: "올바른 이미지 형식이 아닙니다." }, { status: 400 });
        }
        // 크기 검사 (Base64 → 실제 크기 근사)
        const base64Data = avatarUrl.split(",")[1] ?? "";
        const approxBytes = Math.ceil((base64Data.length * 3) / 4);
        if (approxBytes > MAX_SIZE_BYTES) {
            return NextResponse.json({ error: "이미지 크기는 2MB 이하여야 합니다." }, { status: 400 });
        }
    }

    await prisma.$executeRaw`
        UPDATE "User" SET "avatarUrl" = ${avatarUrl ?? null}, "updatedAt" = NOW() WHERE id = ${session.dbId}
    `;

    // 세션 쿠키 갱신
    const sessionSecret = process.env.KAKAO_SESSION_SECRET!;
    const newPayload = {
        provider: session.provider,
        dbId: session.dbId,
        id: session.id,
        email: session.email,
        name: session.name,
        nickname: session.nickname,
        role: session.role,
        issuedAt: Date.now(),
    };
    const newToken = signSession(newPayload, sessionSecret);

    const res = NextResponse.json({ avatarUrl: avatarUrl ?? null });
    res.cookies.set({
        name: SESSION_COOKIE_NAME,
        value: newToken,
        httpOnly: true,
        secure: process.env.NODE_ENV === "production",
        sameSite: "lax",
        path: "/",
        maxAge: SESSION_MAX_AGE_SECONDS,
    });
    return res;
}

import { NextRequest, NextResponse } from "next/server";
import { getServerSession } from "@/lib/session";
import { prisma } from "@/lib/prisma";
import { createHmac } from "crypto";
import { SESSION_COOKIE_NAME, SESSION_MAX_AGE_SECONDS } from "@/lib/constants";

const MAX_SIZE_BYTES = 2 * 1024 * 1024; // 2MB

function signSession(payload: Record<string, unknown>, secret: string) {
    const json = JSON.stringify(payload);
    const signature = createHmac("sha256", secret).update(json).digest("base64url");
    return `${Buffer.from(json).toString("base64url")}.${signature}`;
}

// 프로필 이미지 업로드 (Base64 dataURL)
export async function PATCH(req: NextRequest) {
    try {
        const session = await getServerSession();
        if (!session?.dbId) {
            return NextResponse.json({ error: "로그인이 필요합니다." }, { status: 401 });
        }

        // PRO 구독자 또는 ADMIN만 프로필 사진 변경 가능 (CREATOR도 PRO면 허용)
        const role = String(session.role ?? "USER");
        let canEdit = false;

        if (role === "ADMIN") {
            canEdit = true;
        } else {
            // USER, CREATOR 모두 구독 상태 확인
            const subRows = await prisma.$queryRaw<{ status: string }[]>`
                SELECT status::text FROM "Subscription"
                WHERE "userId" = ${session.dbId}
                LIMIT 1
            `;
            canEdit = subRows.length > 0 && subRows[0].status.toUpperCase() === "ACTIVE";
        }

        if (!canEdit) {
            return NextResponse.json(
                { error: "PRO 구독자만 프로필 사진을 변경할 수 있습니다." },
                { status: 403 }
            );
        }

        const body = await req.json() as { avatarUrl?: string | null };
        const { avatarUrl } = body;

        // null이면 삭제
        if (avatarUrl !== null && avatarUrl !== undefined) {
            if (!avatarUrl.startsWith("data:image/")) {
                return NextResponse.json({ error: "올바른 이미지 형식이 아닙니다." }, { status: 400 });
            }
            const base64Data = avatarUrl.split(",")[1] ?? "";
            const approxBytes = Math.ceil((base64Data.length * 3) / 4);
            if (approxBytes > MAX_SIZE_BYTES) {
                return NextResponse.json({ error: "이미지 크기는 2MB 이하여야 합니다." }, { status: 400 });
            }
        }

        await prisma.$executeRaw`
            UPDATE "User" SET "avatarUrl" = ${avatarUrl ?? null}, "updatedAt" = NOW() WHERE id = ${session.dbId}
        `;

        // 세션 쿠키 갱신
        const sessionSecret = process.env.KAKAO_SESSION_SECRET!;
        const newPayload = {
            provider: session.provider,
            dbId: session.dbId,
            id: session.id,
            email: session.email,
            name: session.name,
            nickname: session.nickname,
            role: session.role,
            issuedAt: Date.now(),
        };
        const newToken = signSession(newPayload, sessionSecret);

        const res = NextResponse.json({ avatarUrl: avatarUrl ?? null });
        res.cookies.set({
            name: SESSION_COOKIE_NAME,
            value: newToken,
            httpOnly: true,
            secure: process.env.NODE_ENV === "production",
            sameSite: "lax",
            path: "/",
            maxAge: SESSION_MAX_AGE_SECONDS,
        });
        return res;
    } catch (e) {
        console.error("[avatar PATCH error]", e);
        return NextResponse.json({ error: "서버 오류가 발생했습니다." }, { status: 500 });
    }
}

"use client";

import React, { useCallback, useEffect, useRef, useState } from "react";

export type BubbleSide = "send" | "receive";

export interface BubbleDesignOptions {
  side: BubbleSide;
  bgColor: string;
  characterUrl?: string;
}

export const DEFAULT_SEND: BubbleDesignOptions = {
  side: "send",
  bgColor: "#FEE500",
  characterUrl: undefined,
};

export const DEFAULT_RECEIVE: BubbleDesignOptions = {
  side: "receive",
  bgColor: "#FFFFFF",
  characterUrl: undefined,
};

// dataURL → objectURL 변환 (동기) — draw 함수보다 반드시 앞에 선언
function dataURLtoObjectURL(dataUrl: string): string {
  const arr  = dataUrl.split(",");
  const mime = arr[0].match(/:(.*?);/)![1];
  const bstr = atob(arr[1]);
  let n = bstr.length;
  const u8arr = new Uint8Array(n);
  while (n--) u8arr[n] = bstr.charCodeAt(n);
  return URL.createObjectURL(new Blob([u8arr], { type: mime }));
}

// ── 좌표 상수
const SEND_BUBBLE  = { cx: 48.10345,  cy: 160.51724, r: 44.48276 };
const SEND_CHAR    = { cx: 125.51724, cy: 68.96552,  r: 62.58621 };
const CANVAS_SIZE  = 210;
const SEND2_W      = 210;
const SEND2_H      = 90;
const SEND2_BUBBLE = { cx: 45.68966, cy: 45.68966,  r: 42.75862 };
const SEND3_W      = 120;
const SEND3_H      = 90;
const SEND3_BUBBLE = { cx: 45.51724, cy: 45.33392,  r: 43.27586 };
const RECEIVE1_W      = 110;
const RECEIVE1_H      = 90;
const RECEIVE1_BUBBLE = { cx: 65.51724, cy: 44.82759, r: 43.27586 };
const RECEIVE2_W      = 110;
const RECEIVE2_H      = 90;
const RECEIVE2_BUBBLE = { cx: 65.51724, cy: 44.82759, r: 43.27586 };

/** bubble-send.svg 기반 PNG 생성 — 동기 */
export function drawBubbleSync(opts: BubbleDesignOptions, charImg: HTMLImageElement | null): string {
  const canvas = document.createElement("canvas");
  canvas.width  = CANVAS_SIZE;
  canvas.height = CANVAS_SIZE;
  const ctx = canvas.getContext("2d")!;
  ctx.clearRect(0, 0, CANVAS_SIZE, CANVAS_SIZE);
  ctx.beginPath();
  ctx.arc(SEND_BUBBLE.cx, SEND_BUBBLE.cy, SEND_BUBBLE.r, 0, Math.PI * 2);
  ctx.fillStyle = opts.bgColor;
  ctx.fill();
  if (charImg) {
    ctx.save();
    ctx.beginPath();
    ctx.arc(SEND_CHAR.cx, SEND_CHAR.cy, SEND_CHAR.r, 0, Math.PI * 2);
    ctx.clip();
    ctx.drawImage(charImg, SEND_CHAR.cx - SEND_CHAR.r, SEND_CHAR.cy - SEND_CHAR.r, SEND_CHAR.r * 2, SEND_CHAR.r * 2);
    ctx.restore();
  }
  return dataURLtoObjectURL(canvas.toDataURL("image/png"));
}

/** bubble-send-2.svg 기반 PNG 생성 — 동기 */
export function drawBubble2SendSync(bgColor: string): string {
  const canvas = document.createElement("canvas");
  canvas.width  = SEND2_W;
  canvas.height = SEND2_H;
  const ctx = canvas.getContext("2d")!;
  ctx.clearRect(0, 0, SEND2_W, SEND2_H);
  ctx.beginPath();
  ctx.arc(SEND2_BUBBLE.cx, SEND2_BUBBLE.cy, SEND2_BUBBLE.r, 0, Math.PI * 2);
  ctx.fillStyle = bgColor;
  ctx.fill();
  return dataURLtoObjectURL(canvas.toDataURL("image/png"));
}

/** bubble-send-3.svg 기반 PNG 생성 — 동기 */
export function drawBubble3SendSync(bgColor: string): string {
  const canvas = document.createElement("canvas");
  canvas.width  = SEND3_W;
  canvas.height = SEND3_H;
  const ctx = canvas.getContext("2d")!;
  ctx.clearRect(0, 0, SEND3_W, SEND3_H);
  ctx.beginPath();
  ctx.ellipse(SEND3_BUBBLE.cx, SEND3_BUBBLE.cy, SEND3_BUBBLE.r, SEND3_BUBBLE.r, 0, 0, Math.PI * 2);
  ctx.fillStyle = bgColor;
  ctx.fill();
  return dataURLtoObjectURL(canvas.toDataURL("image/png"));
}

/** bubble-receive.svg 기반 PNG 생성 — 동기 */
export function drawBubble1ReceiveSync(bgColor: string): string {
  const canvas = document.createElement("canvas");
  canvas.width  = RECEIVE1_W;
  canvas.height = RECEIVE1_H;
  const ctx = canvas.getContext("2d")!;
  ctx.clearRect(0, 0, RECEIVE1_W, RECEIVE1_H);
  ctx.beginPath();
  ctx.arc(RECEIVE1_BUBBLE.cx, RECEIVE1_BUBBLE.cy, RECEIVE1_BUBBLE.r, 0, Math.PI * 2);
  ctx.fillStyle = bgColor;
  ctx.fill();
  return dataURLtoObjectURL(canvas.toDataURL("image/png"));
}

/** bubble-receive-2.svg 기반 PNG 생성 — 동기 */
export function drawBubble2ReceiveSync(bgColor: string): string {
  const canvas = document.createElement("canvas");
  canvas.width  = RECEIVE2_W;
  canvas.height = RECEIVE2_H;
  const ctx = canvas.getContext("2d")!;
  ctx.clearRect(0, 0, RECEIVE2_W, RECEIVE2_H);
  ctx.beginPath();
  ctx.arc(RECEIVE2_BUBBLE.cx, RECEIVE2_BUBBLE.cy, RECEIVE2_BUBBLE.r, 0, Math.PI * 2);
  ctx.fillStyle = bgColor;
  ctx.fill();
  return dataURLtoObjectURL(canvas.toDataURL("image/png"));
}

// ────────────────────────────────────────────────────────────────
// BubbleDesigner UI
// ────────────────────────────────────────────────────────────────

interface BubbleDesignerProps {
  side: BubbleSide;
  options: BubbleDesignOptions;
  onChange: (opts: BubbleDesignOptions) => void;
  onGenerate: (urls: { bubble1: string; bubble2: string }) => void;
}

export function BubbleDesigner({ side, options, onChange, onGenerate }: BubbleDesignerProps) {
  const charInputRef   = useRef<HTMLInputElement>(null);
  const [charImgEl, setCharImgEl]           = useState<HTMLImageElement | null>(null);
  const [charPreviewUrl, setCharPreviewUrl] = useState<string | null>(null);
  const [status, setStatus]                 = useState<"idle" | "generating" | "done">("idle");
  const prevUrlsRef  = useRef<{ bubble1: string; bubble2: string } | null>(null);
  const restoredRef  = useRef(false);

  // 로컬 색상 (미리보기 원형 즉시 반영용)
  const [localBgColor, setLocalBgColor] = useState(options.bgColor);
  useEffect(() => { setLocalBgColor(options.bgColor); }, [options.bgColor]);

  // rAF 스로틀용 ref
  const rafRef      = useRef<number | null>(null);
  const pendingColor = useRef(options.bgColor);

  // 테마 복원 시 characterUrl 복원
  useEffect(() => {
    if (restoredRef.current) return;
    if (options.characterUrl) {
      restoredRef.current = true;
      setCharPreviewUrl(options.characterUrl);
      const img = new Image();
      img.onload = () => setCharImgEl(img);
      img.src = options.characterUrl;
    }
  }, [options.characterUrl]);

  // 동기 생성 — options 확정 시에만
  const autoGenerate = useCallback(
    (opts: BubbleDesignOptions, img: HTMLImageElement | null) => {
      setStatus("generating");
      try {
        if (prevUrlsRef.current) {
          URL.revokeObjectURL(prevUrlsRef.current.bubble1);
          URL.revokeObjectURL(prevUrlsRef.current.bubble2);
        }
        const url1 = opts.side === "send"
          ? (img ? drawBubbleSync(opts, img) : drawBubble3SendSync(opts.bgColor))
          : drawBubble1ReceiveSync(opts.bgColor);
        const url2 = opts.side === "send"
          ? (img ? drawBubble2SendSync(opts.bgColor) : drawBubble3SendSync(opts.bgColor))
          : drawBubble2ReceiveSync(opts.bgColor);
        prevUrlsRef.current = { bubble1: url1, bubble2: url2 };
        onGenerate({ bubble1: url1, bubble2: url2 });
        setStatus("done");
      } catch {
        setStatus("idle");
      }
    },
    [onGenerate]
  );

  useEffect(() => {
    autoGenerate(options, charImgEl);
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [options, charImgEl]);

  // rAF 스로틀: 드래그 중 상위 onChange 전파를 1프레임에 1번만
  const scheduleOnChange = useCallback((color: string) => {
    pendingColor.current = color;
    if (rafRef.current !== null) return;
    rafRef.current = requestAnimationFrame(() => {
      rafRef.current = null;
      onChange({ ...options, bgColor: pendingColor.current });
    });
  }, [onChange, options]);

  useEffect(() => () => { if (rafRef.current !== null) cancelAnimationFrame(rafRef.current); }, []);

  const handleCharUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const url = URL.createObjectURL(file);
    setCharPreviewUrl(url);
    const img = new Image();
    img.onload = () => setCharImgEl(img);
    img.src = url;
    onChange({ ...options, characterUrl: url });
  };

  const handleRemoveChar = () => {
    setCharPreviewUrl(null);
    setCharImgEl(null);
    if (charInputRef.current) charInputRef.current.value = "";
    onChange({ ...options, characterUrl: undefined });
  };

  const label = side === "send" ? "보낸 메시지" : "받은 메시지";

  return (
    <div className="flex flex-col gap-3 py-2">
      {/* 상태 표시 */}
      <div className="mx-2.5 flex items-center gap-2 py-1.5 px-3 rounded-lg"
        style={{ backgroundColor: status === "done" ? "rgba(34,197,94,0.08)" : status === "generating" ? "rgba(251,146,60,0.08)" : "rgba(0,0,0,0.03)" }}>
        <span className="text-[10px]">
          {status === "generating" ? "⏳" : status === "done" ? "✅" : "⬜"}
        </span>
        <span className="text-[11px] font-medium"
          style={{ color: status === "done" ? "rgb(22,163,74)" : status === "generating" ? "rgb(251,146,60)" : "#9ca3af" }}>
          {status === "generating" ? "목업에 반영 중..." : status === "done" ? `${label} 말풍선 목업에 반영됨` : "설정을 변경하면 목업에 자동 반영됩니다"}
        </span>
      </div>

      {/* 말풍선 색상 */}
      <div className="flex items-center justify-between px-2.5 py-1">
        <span className="text-[12px] font-medium text-gray-500">말풍선 색상</span>
        <div className="flex items-center gap-2">
          <label className="relative cursor-pointer">
            <input
              type="color"
              value={localBgColor}
              onChange={(e) => {
                const v = e.target.value;
                setLocalBgColor(v);
                scheduleOnChange(v);
              }}
              className="opacity-0 absolute inset-0 w-full h-full cursor-pointer z-10"
            />
            <div className="w-5 h-5 rounded-full ring-1 ring-black/10 shadow-sm" style={{ backgroundColor: localBgColor }} />
          </label>
          <span className="text-[11px] font-mono text-gray-400 w-[56px] uppercase">{localBgColor}</span>
        </div>
      </div>

      {/* 캐릭터 이미지 (send만 표시) */}
      {side === "send" && (
        <div className="px-2.5 py-1">
          <div className="flex items-center justify-between mb-1.5">
            <div className="flex flex-col">
              <span className="text-[12px] font-medium text-gray-500">캐릭터 이미지</span>
              <span className="text-[10px] text-gray-400">선택사항입니다</span>
            </div>
            {charPreviewUrl ? (
              <button type="button" onClick={handleRemoveChar}
                className="text-[10px] text-red-500 px-2 py-0.5 bg-red-50 rounded-md">
                삭제
              </button>
            ) : (
              <label className="cursor-pointer flex items-center gap-1 text-[10px] text-orange-500 px-2 py-0.5 bg-orange-50 rounded-md">
                <svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                  <path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/>
                  <polyline points="17 8 12 3 7 8"/><line x1="12" y1="3" x2="12" y2="15"/>
                </svg>
                업로드
                <input ref={charInputRef} type="file" accept="image/*" className="hidden" onChange={handleCharUpload} />
              </label>
            )}
          </div>
          {charPreviewUrl && (
            // eslint-disable-next-line @next/next/no-img-element
            <img src={charPreviewUrl} alt="캐릭터" className="w-12 h-12 object-contain rounded-lg border border-gray-100" />
          )}
        </div>
      )}
    </div>
  );
}

