    chatListSelectedBgAlpha: config.selectedBgAlpha,
    passcodeBgImageUrl: passcodeBgMode === "image" ? (passcodeBgImgUrl || undefined) : undefined,
    bulletEmptyColor: bulletEmptyMode === "color" ? bulletEmptyColor : undefined,
