                        onClick={() => set("darkMode")(false)}
                        className="flex-1 py-1.5 text-[11px] font-semibold transition-colors"
                        style={{
                          backgroundColor: !config.darkMode ? "rgb(251,146,60)" : "#fff",
                          color: !config.darkMode ? "#fff" : "#9ca3af",
                        }}
                      >
                        light
                      </button>
                      <button
                        onClick={() => set("darkMode")(true)}
                        className="flex-1 py-1.5 text-[11px] font-semibold transition-colors"
                        style={{
                          backgroundColor: config.darkMode ? "rgb(251,146,60)" : "#fff",
                          color: config.darkMode ? "#fff" : "#9ca3af",
                        }}
                      >
                        dark
                      </button>
