                                    <div className="w-10 h-10 rounded-full overflow-hidden flex items-center justify-center shrink-0" style={{ background: "#ffe500" }}>
                                        {session.avatarUrl ? (
                                            <Image src={session.avatarUrl} alt={displayNickname} width={40} height={40} className="w-full h-full object-cover" unoptimized />
                                        ) : (
                                            <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="#3A1D1D" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="8" r="4" /><path d="M4 20c0-4 3.6-7 8-7s8 3 8 7" /></svg>
                                        )}
                                    </div>
                                    <div className="flex-1">
                                        <p className="text-[14px] font-semibold" style={{ color: "#1c1917" }}>{displayNickname}</p>
                                        <p className="text-[12px]" style={{ color: "#a8a29e" }}>{session.email ?? "이메일 없음"}</p>
                                    </div>
                                    <span className="text-[11px] font-semibold px-2.5 py-1 rounded-full" style={{ background: "rgba(255,59,48,0.08)", color: "#ff3b30" }}>탈퇴 예정</span>
                                </div>

                                {/* 주의사항 체크리스트 */}
                                <div className="mt-8 mb-2">
                                    <div className="flex items-center gap-3 mb-6">
                                        <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="#ff3b30" strokeWidth="2.2" strokeLinecap="round" strokeLinejoin="round"><path d="M10.29 3.86L1.82 18a2 2 0 0 0 1.71 3h16.94a2 2 0 0 0 1.71-3L13.71 3.86a2 2 0 0 0-3.42 0z" /><line x1="12" y1="9" x2="12" y2="13" /><line x1="12" y1="17" x2="12.01" y2="17" /></svg>
                                        <span className="text-[11px] font-semibold tracking-wide uppercase" style={{ color: "#ff3b30" }}>탈퇴 전 반드시 확인하세요</span>
                                        <div className="flex-1 h-px" style={{ backgroundColor: "rgba(255,59,48,0.15)" }} />
                                    </div>
                                    <div className="flex flex-col gap-1">
                                        {CHECKLIST.map((text, idx) => (
                                            <button key={idx} type="button" onClick={() => toggleWithdrawCheck(idx)} className="flex items-start gap-3 text-left py-3 transition-opacity hover:opacity-70">
                                                <div className="shrink-0 w-4 h-4 rounded mt-0.5 flex items-center justify-center transition-all" style={{ background: withdrawChecked[idx] ? "#ff3b30" : "transparent", border: `1.5px solid ${withdrawChecked[idx] ? "#ff3b30" : "#d6d3d1"}` }}>
                                                    {withdrawChecked[idx] && <svg width="9" height="9" viewBox="0 0 24 24" fill="none" stroke="#fff" strokeWidth="3.5" strokeLinecap="round" strokeLinejoin="round"><path d="M20 6L9 17l-5-5" /></svg>}
                                                </div>
                                                <span className="text-[13px] leading-relaxed" style={{ color: "#78716c" }}>{text}</span>
                                            </button>
                                        ))}
                                    </div>
                                    {!withdrawAllChecked && <p className="mt-3 text-[11px]" style={{ color: "#a8a29e" }}>위 항목을 모두 체크해야 탈퇴를 진행할 수 있습니다.</p>}
                                </div>

                                {/* 확인 문구 입력 */}
                                <div className="mt-8 flex flex-col gap-3" style={{ opacity: withdrawAllChecked ? 1 : 0.4, pointerEvents: withdrawAllChecked ? "auto" : "none" }}>
                                    <div className="flex items-center gap-3 mb-2">
                                        <span className="text-[11px] font-semibold tracking-wide uppercase" style={{ color: "#a8a29e" }}>탈퇴 확인</span>
                                        <div className="flex-1 h-px" style={{ backgroundColor: "#e7e5e4" }} />
                                    </div>
                                    <p className="text-[12px]" style={{ color: "#78716c" }}>아래 입력창에 <span className="font-bold" style={{ color: "#ff3b30" }}>{WITHDRAW_CONFIRM_TEXT}</span> 를 입력하세요.</p>
                                    <input type="text" value={withdrawConfirmInput} onChange={(e) => setWithdrawConfirmInput(e.target.value)} placeholder={WITHDRAW_CONFIRM_TEXT} className="px-0 py-2.5 text-[14px] outline-none bg-transparent w-full max-w-[280px]" style={{ borderBottom: `1.5px solid ${withdrawConfirmMatch ? "#ff3b30" : "#d6d3d1"}`, color: "#1c1917" }} />
                                </div>

                                {withdrawError && <p className="mt-4 text-[13px]" style={{ color: "#ff3b30" }}>{withdrawError}</p>}

                                <div className="flex gap-3 mt-10">
                                    <button onClick={() => setActiveMenu("회원 정보")} className="flex-1 py-3 rounded-xl text-[14px] font-medium transition-opacity hover:opacity-60" style={{ border: "1px solid #e7e5e4", color: "#78716c", background: "transparent" }}>취소</button>
                                    <button onClick={handleWithdraw} disabled={!canWithdraw} className="flex-1 py-3 rounded-xl text-[14px] font-semibold transition-opacity disabled:opacity-30" style={{ background: canWithdraw ? "#ff3b30" : "#ff3b30", color: "#fff" }}>
                                        {withdrawLoading ? "탈퇴 처리 중..." : "탈퇴하기"}
                                    </button>
                                </div>
                            </>
                        ) : null}
                    </>
                ) : (
                    <div className="flex flex-col items-center justify-center py-32 gap-4">
                        <div className="w-12 h-12 rounded-full flex items-center justify-center" style={{ background: "#f5f5f4" }}>
                            <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="#a8a29e" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
                                <circle cx="12" cy="8" r="4" /><path d="M4 20c0-4 3.6-7 8-7s8 3 8 7" />
                            </svg>
                        </div>
                        <div className="flex flex-col gap-1.5 text-center">
                            <h2 className="text-[20px] font-bold" style={{ color: "#1c1917", letterSpacing: "-0.02em" }}>로그인이 필요해요</h2>
                            <p className="text-[13px]" style={{ color: "#a8a29e" }}>마이페이지를 이용하려면 카카오 로그인을 해주세요.</p>
                        </div>
                        <a href="/api/auth/kakao" className="mt-2">
                            <button className="px-7 py-3 rounded-xl text-[14px] font-bold transition-opacity hover:opacity-80 active:scale-95" style={{ background: "rgba(255,231,58,0.95)", color: "#3A1D1D" }}>
                                카카오 로그인
                            </button>
                        </a>
                    </div>
                )}
            </main>
        </div>
    );
}

import { cookies } from "next/headers";
import { createHmac } from "crypto";
import { Suspense } from "react";
import Header from "../components/Header";
import { prisma } from "@/lib/prisma";
import MyPageClient from "./MyPageClient";

const SESSION_COOKIE_NAME = "kakkumi_session";

function verifySession(token: string, secret: string) {
    const [payloadB64, signature] = token.split(".");
    if (!payloadB64 || !signature) return null;
    const json = Buffer.from(payloadB64, "base64url").toString("utf8");
    const expectedSignature = createHmac("sha256", secret).update(json).digest("base64url");
    if (signature !== expectedSignature) return null;
    return JSON.parse(json) as Record<string, unknown>;
}

async function getSession() {
    try {
        const sessionSecret = process.env.KAKAO_SESSION_SECRET;
        if (!sessionSecret) return null;
        const cookieStore = await cookies();
        const sessionCookie = cookieStore.get(SESSION_COOKIE_NAME);
        if (!sessionCookie) return null;
        const session = verifySession(sessionCookie.value, sessionSecret);
        return session as { name?: string | null; nickname?: string | null; image?: string | null; avatarUrl?: string | null; id?: string | null; dbId?: string | null; email?: string | null; role?: string | null } | null;
    } catch {
        return null;
    }
}

export default async function MyPage() {
    const session = await getSession();

    let purchasedCount = 0;
    let createdAt: string | null = null;
    let credit = 0;
    let dbAvatarUrl: string | null = null;
    let isPro = false;

        purchasedCount = await prisma.purchase.count({
            where: { buyerId: session.dbId, status: "COMPLETED" },
        });
        try {
            const rows = await prisma.$queryRaw<{ createdAt: Date; credit: number; avatarUrl: string | null }[]>`
                SELECT "createdAt", credit, "avatarUrl" FROM "User" WHERE id = ${session.dbId} LIMIT 1
            `;
            createdAt = rows[0]?.createdAt?.toISOString() ?? null;
            credit = rows[0]?.credit ?? 0;
            dbAvatarUrl = rows[0]?.avatarUrl ?? null;
        } catch {
            createdAt = null;
        }

        // 구독 상태 직접 확인 (캐시 없이, pricing/page.tsx와 동일한 방식)
            items: [{ label: "회원 정보" }, { label: "알림 설정" }],
        },
        {
            category: "테마",
            items: [{ label: "업로드 테마" }, { label: "구매 테마" }],
        },
        {
            category: "쇼핑",
            items: [
                { label: "리뷰" }, { label: "적립금" }, { label: "작성 가능한 후기" },
                { label: "주문 내역" }, { label: "취소/환불 내역" }, { label: "좋아요" }, { label: "팔로우" },
            ],
        },
        {
            category: "수익",
            items: [{ label: "정산 내역" }, { label: "판매 통계" }, { label: "정산 계좌" }],
        },
        {
            category: "계정",
            items: [{ label: "결제 정보" }, { label: "결제 내역" }, { label: "회원 탈퇴" }],
        },
    ];

    const sessionWithAvatar = session ? { ...session, avatarUrl: dbAvatarUrl } : null;

    return (
        <div
            className="min-h-screen flex flex-col mac-scroll"
            style={{
                backgroundColor: "#f3f3f3",
            }}
        >
            <Header />
            <Suspense fallback={<div className="flex-1 flex items-center justify-center py-24"><div className="w-10 h-10 rounded-full border-4 border-gray-200 border-t-gray-500 animate-spin" /></div>}>
                <MyPageClient
                    session={sessionWithAvatar}
                    purchasedCount={purchasedCount}
                    sidebarMenus={sidebarMenus}
                    createdAt={createdAt}
                    credit={credit}
                    isPro={isPro}
                />
            </Suspense>
        </div>
    );
}

import { cookies } from "next/headers";
import { createHmac } from "crypto";
import { Suspense } from "react";
import Header from "../components/Header";
import { prisma } from "@/lib/prisma";
import MyPageClient from "./MyPageClient";

export const dynamic = "force-dynamic";

const SESSION_COOKIE_NAME = "kakkumi_session";

function verifySession(token: string, secret: string) {
    const [payloadB64, signature] = token.split(".");
    if (!payloadB64 || !signature) return null;
    const json = Buffer.from(payloadB64, "base64url").toString("utf8");
    const expectedSignature = createHmac("sha256", secret).update(json).digest("base64url");
    if (signature !== expectedSignature) return null;
    return JSON.parse(json) as Record<string, unknown>;
}

async function getSession() {
    try {
        const sessionSecret = process.env.KAKAO_SESSION_SECRET;
        if (!sessionSecret) return null;
        const cookieStore = await cookies();
        const sessionCookie = cookieStore.get(SESSION_COOKIE_NAME);
        if (!sessionCookie) return null;
        const session = verifySession(sessionCookie.value, sessionSecret);
        return session as { name?: string | null; nickname?: string | null; image?: string | null; avatarUrl?: string | null; id?: string | null; dbId?: string | null; email?: string | null; role?: string | null } | null;
    } catch {
        return null;
    }
}

export default async function MyPage() {
    const session = await getSession();

    let purchasedCount = 0;
    let createdAt: string | null = null;
    let credit = 0;
    let dbAvatarUrl: string | null = null;
    let isPro = false;

    if (session?.dbId) {
        purchasedCount = await prisma.purchase.count({
            where: { buyerId: session.dbId, status: "COMPLETED" },
        });
        try {
            const rows = await prisma.$queryRaw<{ createdAt: Date; credit: number; avatarUrl: string | null }[]>`
                SELECT "createdAt", credit, "avatarUrl" FROM "User" WHERE id = ${session.dbId} LIMIT 1
            `;
            createdAt = rows[0]?.createdAt?.toISOString() ?? null;
            credit = rows[0]?.credit ?? 0;
            dbAvatarUrl = rows[0]?.avatarUrl ?? null;
        } catch {
            createdAt = null;
        }

        // 구독 상태 직접 확인 (CREATOR 포함 모든 role 체크)
        const role = session.role ?? "USER";
        if (role === "ADMIN") {
            isPro = true;
        } else {
            // USER, CREATOR 모두 PRO 구독 여부 확인
            const sub = await prisma.subscription.findUnique({ where: { userId: session.dbId } });
            isPro = !!sub && String(sub.status).toUpperCase() === "ACTIVE";
        }
    }

    const sidebarMenus = [
        {
            category: "정보",
            items: [{ label: "회원 정보" }, { label: "알림 설정" }],
        },
        {
            category: "테마",
            items: [{ label: "업로드 테마" }, { label: "구매 테마" }],
        },
        {
            category: "쇼핑",
            items: [
                { label: "리뷰" }, { label: "적립금" }, { label: "작성 가능한 후기" },
                { label: "주문 내역" }, { label: "취소/환불 내역" }, { label: "좋아요" }, { label: "팔로우" },
            ],
        },
        {
            category: "수익",
            items: [{ label: "정산 내역" }, { label: "판매 통계" }, { label: "정산 계좌" }],
        },
        {
            category: "계정",
            items: [{ label: "결제 정보" }, { label: "결제 내역" }, { label: "회원 탈퇴" }],
        },
    ];

    const sessionWithAvatar = session ? { ...session, avatarUrl: dbAvatarUrl } : null;

    return (
        <div
            className="min-h-screen flex flex-col mac-scroll"
            style={{
                backgroundColor: "#f3f3f3",
            }}
        >
            <Header />
            <Suspense fallback={<div className="flex-1 flex items-center justify-center py-24"><div className="w-10 h-10 rounded-full border-4 border-gray-200 border-t-gray-500 animate-spin" /></div>}>
                <MyPageClient
                    session={sessionWithAvatar}
                    purchasedCount={purchasedCount}
                    sidebarMenus={sidebarMenus}
                    createdAt={createdAt}
                    credit={credit}
                    isPro={isPro}
                />
            </Suspense>
        </div>
    );
}

"use client";

import { useState, useEffect, useRef } from "react";
import { useRouter } from "next/navigation";
import { validateNickname } from "@/lib/nickname";
import Image from "next/image";

export default function OnboardingPage() {
    const router = useRouter();
    const [nickname, setNickname] = useState("");
    const [error, setError] = useState("");
    const [checkStatus, setCheckStatus] = useState<"idle" | "checking" | "available" | "taken">("idle");
    const [saving, setSaving] = useState(false);
    const [referralCode, setReferralCode] = useState("");
    const [referralMsg, setReferralMsg] = useState<{ ok: boolean; text: string } | null>(null);
    const debounceRef = useRef<ReturnType<typeof setTimeout> | null>(null);

    // 프로필 이미지 상태
    const [avatarPreview, setAvatarPreview] = useState<string | null>(null);
    const [avatarError, setAvatarError] = useState("");
    const fileInputRef = useRef<HTMLInputElement>(null);

    // 입력할 때마다 실시간 중복 체크 (debounce)
    useEffect(() => {
        if (debounceRef.current) clearTimeout(debounceRef.current);

        debounceRef.current = setTimeout(() => {
            const validationError = validateNickname(nickname);
            if (validationError) {
                setError(validationError);
                setCheckStatus("idle");
                return;
            }

            setError("");
            setCheckStatus("checking");

            fetch(`/api/user/nickname/check?nickname=${encodeURIComponent(nickname)}`)
                .then((res) => res.json())
                .then((data: { available: boolean; error?: string }) => {
                    if (data.error) {
                        setError(data.error);
                        setCheckStatus("idle");
                    } else {
                        setCheckStatus(data.available ? "available" : "taken");
                        if (!data.available) setError("이미 사용 중인 닉네임입니다.");
                    }
                })
                .catch(() => setCheckStatus("idle"));
        }, 500);
    }, [nickname]);

    const handleAvatarChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;
        if (!file.type.startsWith("image/")) {
            setAvatarError("이미지 파일만 업로드할 수 있습니다.");
            return;
        }
        if (file.size > 2 * 1024 * 1024) {
            setAvatarError("이미지 크기는 2MB 이하여야 합니다.");
            return;
        }
        setAvatarError("");
        const reader = new FileReader();
        reader.onload = (ev) => {
            setAvatarPreview(ev.target?.result as string);
        };
        reader.readAsDataURL(file);
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (checkStatus !== "available" || saving) return;

        setSaving(true);

        // 1) 닉네임 + 추천인 코드 저장
        const res = await fetch("/api/user/nickname", {
            method: "PATCH",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ nickname, referralCode: referralCode.trim() || null }),
        });
        const data = await res.json() as { nickname?: string; error?: string };

        if (!res.ok) {
            const errorMsg = data.error ?? "저장 실패";
            if (errorMsg.includes("닉네임")) {
                setReferralMsg({ ok: false, text: errorMsg });
            } else {
                setError(errorMsg);
            }
            setSaving(false);
            return;
        }

        // 2) 프로필 이미지 저장 (선택한 경우만)
        if (avatarPreview) {
            await fetch("/api/user/avatar", {
                method: "PATCH",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ avatarUrl: avatarPreview }),
            });
        }

        setSaving(false);
        router.push("/");
    };

    return (
        <div
            className="min-h-screen flex flex-col items-center justify-center px-4"
            style={{
                backgroundColor: "#f3f3f3",
            }}
        >
            <div
                className="w-full max-w-[440px] flex flex-col gap-7 p-10 rounded-[28px]"
                style={{
                    background: "rgba(255,255,255,0.85)",
                    backdropFilter: "blur(20px)",
                    boxShadow: "0 8px 40px rgba(0,0,0,0.08)",
                    border: "1px solid rgba(255,255,255,0.9)",
                }}
            >
                {/* 로고 */}
                <div className="flex flex-col items-center gap-3">
                    <Image src="/카꾸미.png" alt="카꾸미" width={52} height={52} className="rounded-[14px]" />
                    <div className="flex flex-col items-center gap-1">
                        <h1 className="text-[22px] font-extrabold" style={{ color: "#1c1c1e", fontFamily: "'ChosunIlboMyungjo', serif" }}>
                            카꾸미에 오신 걸 환영해요!
                        </h1>
                        <p className="text-[13px] text-center leading-relaxed" style={{ color: "#8e8e93" }}>
                            프로필을 설정하고 시작해보세요.
                        </p>
                    </div>
                </div>

                {/* 입력 폼 */}
                <form onSubmit={handleSubmit} className="flex flex-col gap-6">

                    {/* 프로필 이미지 (선택) */}
                    <div className="flex flex-col items-center gap-3">
                        <button
                            type="button"
                            onClick={() => fileInputRef.current?.click()}
                            className="relative group w-24 h-24 rounded-full overflow-hidden flex items-center justify-center transition-all hover:opacity-90 active:scale-95"
                            style={{ background: avatarPreview ? 'transparent' : 'rgba(195,195,195,0.5)', boxShadow: "0 2px 12px rgba(0,0,0,0.1)" }}
                        >
                            {avatarPreview ? (
                                <Image src={avatarPreview} alt="프로필 미리보기" fill className="object-cover" unoptimized />
                            ) : (
                                <svg width="36" height="36" viewBox="0 0 24 24" fill="none" stroke="#3A1D1D" strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round">
                                    <circle cx="12" cy="8" r="4" />
                                    <path d="M4 20c0-4 3.6-7 8-7s8 3 8 7" />
                                </svg>
                            )}
                            {/* 오버레이 */}
                            <div
                                className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity"
                                style={{ background: "rgba(0,0,0,0.35)" }}
                            >
                                <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="#fff" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                                    <path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4" />
                                    <polyline points="17 8 12 3 7 8" />
                                    <line x1="12" y1="3" x2="12" y2="15" />
                                </svg>
                            </div>
                        </button>
                        <input
                            ref={fileInputRef}
                            type="file"
                            accept="image/*"
                            className="hidden"
                            onChange={handleAvatarChange}
                        />
                        <div className="flex flex-col items-center gap-0.5">
                            <span className="text-[12px] font-medium" style={{ color: "#3a3a3c" }}>
                                프로필 사진 <span className="text-[11px]" style={{ color: "#8e8e93" }}>(선택)</span>
                            </span>
                            {avatarPreview && (
                                <button
                                    type="button"
                                    onClick={() => { setAvatarPreview(null); if (fileInputRef.current) fileInputRef.current.value = ""; }}
                                    className="text-[11px] transition-all hover:opacity-70"
                                    style={{ color: "#ff3b30" }}
                                >
                                    사진 제거
                                </button>
                            )}
                            {avatarError && <p className="text-[11px]" style={{ color: "#ff3b30" }}>{avatarError}</p>}
                        </div>
                    </div>

                    {/* 닉네임 */}
                    <div className="flex flex-col gap-3">
                        {/* 규칙 안내 */}
                        <div
                            className="flex flex-col gap-1.5 px-4 py-3 rounded-[12px] text-[12px] leading-relaxed"
                            style={{ background: "rgba(74,123,247,0.07)", color: "#3a5a8a" }}
                        >
                            <p className="font-semibold">닉네임 규칙</p>
                            <ul className="flex flex-col gap-0.5 list-disc list-inside" style={{ color: "#48484a" }}>
                                <li>2~10자 이내</li>
                                <li>한글, 영문, 숫자 사용 가능</li>
                                <li>특수문자 불가</li>
                                <li>숫자만으로는 설정 불가</li>
                            </ul>
                        </div>

                        <div className="flex flex-col gap-1.5">
                            <label className="text-[12px] font-semibold" style={{ color: "#3a3a3c" }}>
                                닉네임 <span style={{ color: "#FF3B30" }}>*</span>
                            </label>
                            <div className="relative">
                                <input
                                    type="text"
                                    value={nickname}
                                    onChange={(e) => setNickname(e.target.value)}
                                    placeholder="닉네임을 입력해주세요"
                                    maxLength={10}
                                    autoFocus
                                    className="w-full px-4 py-3 rounded-xl text-[14px] outline-none pr-10"
                                    style={{
                                        background: "rgba(255,255,255,0.9)",
                                        border: `1.5px solid ${
                                            checkStatus === "available" ? "#34c759"
                                            : checkStatus === "taken" || error ? "#ff3b30"
                                            : "rgba(0,0,0,0.12)"
                                        }`,
                                        color: "#1c1c1e",
                                        transition: "border-color 0.15s",
                                    }}
                                />
                                {/* 상태 아이콘 */}
                                <div className="absolute right-3 top-1/2 -translate-y-1/2">
                                    {checkStatus === "checking" && (
                                        <div className="w-4 h-4 rounded-full border-2 border-black/20 border-t-black/60 animate-spin" />
                                    )}
                                    {checkStatus === "available" && (
                                        <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#34c759" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                                            <path d="M20 6L9 17l-5-5" />
                                        </svg>
                                    )}
                                    {checkStatus === "taken" && (
                                        <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#ff3b30" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                                            <line x1="18" y1="6" x2="6" y2="18" /><line x1="6" y1="6" x2="18" y2="18" />
                                        </svg>
                                    )}
                                </div>
                            </div>

                            {/* 상태 메시지 */}
                            <div className="flex items-center justify-between">
                                <p className="text-[11px]" style={{ color: checkStatus === "available" ? "#34c759" : "#ff3b30", minHeight: 16 }}>
                                    {checkStatus === "available" ? "사용 가능한 닉네임입니다." : error}
                                </p>
                                <p className="text-[11px]" style={{ color: "#8e8e93" }}>{nickname.length} / 10</p>
                            </div>
                        </div>
                    </div>

                    {/* 추천인 닉네임 (선택) */}
                    <div className="flex flex-col gap-1.5">
                        <label className="text-[12px] font-semibold flex items-center gap-1" style={{ color: "#3a3a3c" }}>
                            추천인 닉네임
                            <span className="text-[11px] font-normal" style={{ color: "#8e8e93" }}>(선택 · 입력 시 500원 적립)</span>
                        </label>
                        <input
                            type="text"
                            value={referralCode}
                            onChange={e => { setReferralCode(e.target.value); setReferralMsg(null); }}
                            placeholder="추천인의 카꾸미 닉네임을 입력해주세요"
                            maxLength={10}
                            className="w-full px-4 py-3 rounded-xl text-[14px] outline-none"
                            style={{
                                background: "rgba(255,255,255,0.9)",
                                border: `1.5px solid ${referralMsg?.ok === false ? "#ff3b30" : referralMsg?.ok === true ? "#34c759" : "rgba(0,0,0,0.12)"}`,
                                color: "#1c1c1e",
                                transition: "border-color 0.15s",
                            }}
                        />
                        {referralMsg && (
                            <p className="text-[11px]" style={{ color: referralMsg.ok ? "#34c759" : "#ff3b30" }}>{referralMsg.text}</p>
                        )}
                    </div>

                    <button
                        type="submit"
                        disabled={checkStatus !== "available" || saving}
                        className="w-full py-3.5 rounded-xl text-[15px] font-bold transition-all hover:brightness-105 active:scale-[0.98] disabled:opacity-40"
                        style={{ background: "rgba(255,231,58,0.95)", color: "#3A1D1D", boxShadow: "0 4px 16px rgba(255,200,0,0.25)" }}
                    >
                        {saving ? "저장 중..." : "시작하기"}
                    </button>
                </form>
            </div>
        </div>
    );
}

"use client";

import { useState, useEffect, useRef } from "react";
import { useRouter } from "next/navigation";
import { validateNickname } from "@/lib/nickname";
import Image from "next/image";

export default function OnboardingPage() {
    const router = useRouter();
    const [nickname, setNickname] = useState("");
    const [error, setError] = useState("");
    const [checkStatus, setCheckStatus] = useState<"idle" | "checking" | "available" | "taken">("idle");
    const [saving, setSaving] = useState(false);
    const [referralCode, setReferralCode] = useState("");
    const [referralMsg, setReferralMsg] = useState<{ ok: boolean; text: string } | null>(null);
    const debounceRef = useRef<ReturnType<typeof setTimeout> | null>(null);


    // 입력할 때마다 실시간 중복 체크 (debounce)
    useEffect(() => {
        if (debounceRef.current) clearTimeout(debounceRef.current);

        debounceRef.current = setTimeout(() => {
            const validationError = validateNickname(nickname);
            if (validationError) {
                setError(validationError);
                setCheckStatus("idle");
                return;
            }

            setError("");
            setCheckStatus("checking");

            fetch(`/api/user/nickname/check?nickname=${encodeURIComponent(nickname)}`)
                .then((res) => res.json())
                .then((data: { available: boolean; error?: string }) => {
                    if (data.error) {
                        setError(data.error);
                        setCheckStatus("idle");
                    } else {
                        setCheckStatus(data.available ? "available" : "taken");
                        if (!data.available) setError("이미 사용 중인 닉네임입니다.");
                    }
                })
                .catch(() => setCheckStatus("idle"));
        }, 500);
    }, [nickname]);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (checkStatus !== "available" || saving) return;

        setSaving(true);

        // 닉네임 + 추천인 코드 저장
        const res = await fetch("/api/user/nickname", {
            method: "PATCH",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ nickname, referralCode: referralCode.trim() || null }),
        });
        const data = await res.json() as { nickname?: string; error?: string };

        if (!res.ok) {
            const errorMsg = data.error ?? "저장 실패";
            if (errorMsg.includes("닉네임")) {
                setReferralMsg({ ok: false, text: errorMsg });
            } else {
                setError(errorMsg);
            }
            setSaving(false);
            return;
        }


        setSaving(false);
        router.push("/");
    };

    return (
        <div
            className="min-h-screen flex flex-col items-center justify-center px-4"
            style={{
                backgroundColor: "#f3f3f3",
            }}
        >
            <div
                className="w-full max-w-[440px] flex flex-col gap-7 p-10 rounded-[28px]"
                style={{
                    background: "rgba(255,255,255,0.85)",
                    backdropFilter: "blur(20px)",
                    boxShadow: "0 8px 40px rgba(0,0,0,0.08)",
                    border: "1px solid rgba(255,255,255,0.9)",
                }}
            >
                {/* 로고 */}
                <div className="flex flex-col items-center gap-3">
                    <Image src="/카꾸미.png" alt="카꾸미" width={52} height={52} className="rounded-[14px]" />
                    <div className="flex flex-col items-center gap-1">
                        <h1 className="text-[22px] font-extrabold" style={{ color: "#1c1c1e", fontFamily: "'ChosunIlboMyungjo', serif" }}>
                            카꾸미에 오신 걸 환영해요!
                        </h1>
                        <p className="text-[13px] text-center leading-relaxed" style={{ color: "#8e8e93" }}>
                            프로필을 설정하고 시작해보세요.
                        </p>
                    </div>
                </div>

                {/* 입력 폼 */}
                <form onSubmit={handleSubmit} className="flex flex-col gap-6">

                    {/* 닉네임 */}
                    <div className="flex flex-col gap-3">
                        {/* 규칙 안내 */}
                        <div
                            className="flex flex-col gap-1.5 px-4 py-3 rounded-[12px] text-[12px] leading-relaxed"
                            style={{ background: "rgba(74,123,247,0.07)", color: "#3a5a8a" }}
                        >
                            <p className="font-semibold">닉네임 규칙</p>
                            <ul className="flex flex-col gap-0.5 list-disc list-inside" style={{ color: "#48484a" }}>
                                <li>2~10자 이내</li>
                                <li>한글, 영문, 숫자 사용 가능</li>
                                <li>특수문자 불가</li>
                                <li>숫자만으로는 설정 불가</li>
                            </ul>
                        </div>

                        <div className="flex flex-col gap-1.5">
                            <label className="text-[12px] font-semibold" style={{ color: "#3a3a3c" }}>
                                닉네임 <span style={{ color: "#FF3B30" }}>*</span>
                            </label>
                            <div className="relative">
                                <input
                                    type="text"
                                    value={nickname}
                                    onChange={(e) => setNickname(e.target.value)}
                                    placeholder="닉네임을 입력해주세요"
                                    maxLength={10}
                                    autoFocus
                                    className="w-full px-4 py-3 rounded-xl text-[14px] outline-none pr-10"
                                    style={{
                                        background: "rgba(255,255,255,0.9)",
                                        border: `1.5px solid ${
                                            checkStatus === "available" ? "#34c759"
                                            : checkStatus === "taken" || error ? "#ff3b30"
                                            : "rgba(0,0,0,0.12)"
                                        }`,
                                        color: "#1c1c1e",
                                        transition: "border-color 0.15s",
                                    }}
                                />
                                {/* 상태 아이콘 */}
                                <div className="absolute right-3 top-1/2 -translate-y-1/2">
                                    {checkStatus === "checking" && (
                                        <div className="w-4 h-4 rounded-full border-2 border-black/20 border-t-black/60 animate-spin" />
                                    )}
                                    {checkStatus === "available" && (
                                        <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#34c759" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                                            <path d="M20 6L9 17l-5-5" />
                                        </svg>
                                    )}
                                    {checkStatus === "taken" && (
                                        <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#ff3b30" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                                            <line x1="18" y1="6" x2="6" y2="18" /><line x1="6" y1="6" x2="18" y2="18" />
                                        </svg>
                                    )}
                                </div>
                            </div>

                            {/* 상태 메시지 */}
                            <div className="flex items-center justify-between">
                                <p className="text-[11px]" style={{ color: checkStatus === "available" ? "#34c759" : "#ff3b30", minHeight: 16 }}>
                                    {checkStatus === "available" ? "사용 가능한 닉네임입니다." : error}
                                </p>
                                <p className="text-[11px]" style={{ color: "#8e8e93" }}>{nickname.length} / 10</p>
                            </div>
                        </div>
                    </div>

                    {/* 추천인 닉네임 (선택) */}
                    <div className="flex flex-col gap-1.5">
                        <label className="text-[12px] font-semibold flex items-center gap-1" style={{ color: "#3a3a3c" }}>
                            추천인 닉네임
                            <span className="text-[11px] font-normal" style={{ color: "#8e8e93" }}>(선택 · 입력 시 500원 적립)</span>
                        </label>
                        <input
                            type="text"
                            value={referralCode}
                            onChange={e => { setReferralCode(e.target.value); setReferralMsg(null); }}
                            placeholder="추천인의 카꾸미 닉네임을 입력해주세요"
                            maxLength={10}
                            className="w-full px-4 py-3 rounded-xl text-[14px] outline-none"
                            style={{
                                background: "rgba(255,255,255,0.9)",
                                border: `1.5px solid ${referralMsg?.ok === false ? "#ff3b30" : referralMsg?.ok === true ? "#34c759" : "rgba(0,0,0,0.12)"}`,
                                color: "#1c1c1e",
                                transition: "border-color 0.15s",
                            }}
                        />
                        {referralMsg && (
                            <p className="text-[11px]" style={{ color: referralMsg.ok ? "#34c759" : "#ff3b30" }}>{referralMsg.text}</p>
                        )}
                    </div>

                    <button
                        type="submit"
                        disabled={checkStatus !== "available" || saving}
                        className="w-full py-3.5 rounded-xl text-[15px] font-bold transition-all hover:brightness-105 active:scale-[0.98] disabled:opacity-40"
                        style={{ background: "rgba(255,231,58,0.95)", color: "#3A1D1D", boxShadow: "0 4px 16px rgba(255,200,0,0.25)" }}
                    >
                        {saving ? "저장 중..." : "시작하기"}
                    </button>
                </form>
            </div>
        </div>
    );
}

"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import Script from "next/script";
import LoginRequiredModal from "@/app/components/LoginRequiredModal";

type Props = {
    isLoggedIn: boolean;
    isSubscribed: boolean;
    subscriptionStatus: string | null;
    role: string | null;
};

const FREE_FEATURES = [
    { label: "테마 에디터 기본 기능", included: true },
    { label: "내 테마 저장 (최대 5개)", included: true },
    { label: "테마 스토어 이용", included: true },
    { label: "꾸미 갤러리 이용", included: true },
    { label: "무료 테마 다운로드", included: true },
    { label: "테마 복사/복제", included: false },
    { label: "내 테마 저장 무제한", included: false },
    { label: "Pro 전용 프리셋 팔레트", included: false },
    { label: "Pro 전용 프로필 뱃지 ✦", included: false },
    { label: "광고 없는 UI (추후 적용)", included: false },
];

const PRO_FEATURES = [
    { label: "테마 에디터 기본 기능", included: true },
    { label: "내 테마 저장 무제한", included: true },
    { label: "테마 스토어 이용", included: true },
    { label: "꾸미 갤러리 이용", included: true },
    { label: "무료 테마 다운로드", included: true },
    { label: "테마 복사/복제", included: true },
    { label: "Pro 전용 프리셋 팔레트", included: true },
    { label: "Pro 전용 프로필 뱃지 ✦", included: true },
    { label: "광고 없는 UI (추후 적용)", included: true },
];

export default function PricingClient({ isLoggedIn, isSubscribed }: Props) {
    const router = useRouter();
    const [loginModal, setLoginModal] = useState(false);
    const [loading, setLoading] = useState(false);
    const [toast, setToast] = useState("");

    const showToast = (msg: string) => {
        setToast(msg);
        setTimeout(() => setToast(""), 3000);
    };

    const handleSubscribe = async () => {
        if (!isLoggedIn) { setLoginModal(true); return; }
        if (isSubscribed) { showToast("이미 구독 중입니다."); return; }

        setLoading(true);
        try {
            const clientKey = process.env.NEXT_PUBLIC_TOSSPAYMENTS_CLIENT_KEY;
            if (!clientKey) {
                showToast("결제 설정 오류입니다.");
                setLoading(false);
                return;
            }

            const win = window as unknown as Record<string, unknown>;
            const TossPayments = win["TossPayments"] as ((key: string) => { requestPayment: (method: string, opts: Record<string, unknown>) => Promise<void> }) | undefined;
            if (!TossPayments) {
                showToast("결제 모듈 로딩 중입니다. 잠시 후 다시 시도해주세요.");
                setLoading(false);
                return;
            }

            const toss = TossPayments(clientKey);
            const orderId = `sub_${Date.now().toString(36)}`;

            await toss.requestPayment("카드", {
                amount: 4900,
                orderId,
                orderName: "카꾸미 Pro 구독 (1개월)",
                customerName: "카꾸미 고객",
                successUrl: `${window.location.origin}/payment/subscription/success`,
                failUrl: `${window.location.origin}/pricing?fail=1`,
            });
            // requestPayment는 페이지 리다이렉트됨 — 이후 코드 실행 안 됨
        } catch (e: unknown) {
            if (e && typeof e === "object" && "code" in e && (e as { code: string }).code === "USER_CANCEL") {
                showToast("결제가 취소되었습니다.");
            } else {
                showToast("결제 처리 중 오류가 발생했습니다.");
            }
        } finally {
            setLoading(false);
        }
    };

    return (
        <main className="flex-1 w-full max-w-[1200px] mx-auto px-6 pt-16 pb-24">
            {/* 토스트 */}
            {toast && (
                <div className="fixed top-5 left-1/2 -translate-x-1/2 z-50 px-5 py-2.5 rounded-xl text-[13px] font-medium shadow-lg"
                    style={{ background: "#18181b", color: "#fff" }}>
                    {toast}
                </div>
            )}

            {loginModal && (
                <LoginRequiredModal
                    message="구독하려면 로그인이 필요해요."
                    onClose={() => setLoginModal(false)}
                />
            )}

            {/* 헤더 */}
            <div className="text-center mb-16">
                <p className="text-[11px] font-bold tracking-[0.2em] uppercase mb-3" style={{ color: "#FF9500" }}>Pricing</p>
                <h1 className="text-[40px] font-extrabold leading-tight mb-4" style={{ color: "#1c1c1e", fontFamily: "'ChosunIlboMyungjo', serif" }}>
                    카꾸미 요금제
                </h1>
                <p className="text-[16px]" style={{ color: "#8e8e93" }}>
                    더 자유롭게, 더 창의적으로 나만의 테마를 만들어보세요.
                </p>
            </div>

            {/* 플랜 카드 */}
            <div className="grid grid-cols-2 gap-6 max-w-[860px] mx-auto mb-20">

                {/* 무료 플랜 */}
                <div className="rounded-3xl p-8 flex flex-col gap-6"
                    style={{ background: "#fff", border: "1.5px solid rgba(0,0,0,0.07)" }}>
                    <div>
                        <p className="text-[12px] font-bold tracking-widest uppercase mb-2" style={{ color: "#aeaeb2" }}>Free</p>
                        <div className="flex items-end gap-1 mb-1">
                            <span className="text-[40px] font-extrabold" style={{ color: "#1c1c1e" }}>0</span>
                            <span className="text-[18px] font-medium mb-2" style={{ color: "#8e8e93" }}>원 / 월</span>
                        </div>
                        <p className="text-[13px]" style={{ color: "#aeaeb2" }}>기본적인 테마 제작과 스토어 이용</p>
                    </div>

                    <div className="flex flex-col gap-3">
                        {FREE_FEATURES.map((f) => (
                            <div key={f.label} className="flex items-center gap-2.5">
                                {f.included ? (
                                    <svg width="16" height="16" viewBox="0 0 24 24" fill="none" className="shrink-0">
